function togglePanel(): void {
  state.isOpen = !state.isOpen;
  if (state.panel) {
    state.panel.style.transform = state.isOpen ? 'translateX(0)' : 'translateX(-100%)';
  }
  setLeftSidebarShift(state.isOpen ? 300 : 0);
}

export function toggleAdvisorPanel(): void {
  togglePanel();
}

export function initAdvisorPanel(): void {
  registerHudButton('💬 ADVISOR', () => togglePanel(), 'Open ARIA — Asteroid Resource Intelligence Advisor', true);
  const refs = buildAdvisorPanelDOM();
  wireAdvisorPanelEvents(refs);
  document.body.appendChild(state.panel!);

  // Show offline banner if no API key configured
  if (!hasApiKey()) {
    showOfflineBanner();
  }

  // Inject pulse keyframe
  if (!document.getElementById('aria-styles')) {
    const style = document.createElement('style');
    style.id = 'aria-styles';
    style.textContent = `
      @keyframes ariaPulse {
        0%, 100% { opacity: 0.3; transform: scale(0.8); }
        50% { opacity: 1; transform: scale(1.2); }
      }
    `;
    document.head.appendChild(style);
  }
}

export function onPlayerSubmit(callback: (text: string) => void): void {
  state.playerSubmitCallback = callback;
}

export function setLoading(loading: boolean): void {
  if (!state.loadingEl || !state.inputEl || !state.submitBtn) return;
  state.loadingEl.style.display = loading ? 'flex' : 'none';
  state.inputEl.disabled = loading;
  state.submitBtn.disabled = loading;
}

export function setApiKeyStatus(hasKey: boolean, authError: boolean = false): void {
  if (state.statusDot) {
    if (authError) {
      state.statusDot.style.background = '#f59e0b';
      state.statusDot.title = 'API key invalid or expired';
    } else if (hasKey) {
      state.statusDot.style.background = '#22c55e';
      state.statusDot.title = 'API key configured';
    } else {
      state.statusDot.style.background = '#ef4444';
      state.statusDot.title = 'No API key';
    }
  }
}

