import { state } from './state';
import { sessionOptBackIn } from '../../advisor/usage';
import { updateSessionUsageEl, updateUsageSummaryEl } from './usageDisplay';
import { showApiKeyInput } from './settingsOverlay';
import { handleSubmit } from './messages';

export const PANEL_STYLES = `
  position: fixed;
  top: 0;
  left: 0;
  width: 300px;
  height: 100vh;
  background: rgba(0, 6, 18, 0.85);
  border-right: 1px solid rgba(0, 200, 255, 0.2);
  display: flex;
  flex-direction: column;
  z-index: 50;
  font-family: 'Courier New', monospace;
  font-size: 11px;
  color: #9ecfdf;
  transform: translateX(-100%);
  transition: transform 0.25s ease;
  pointer-events: all;
`;

export interface AdvisorPanelRefs {
  panel: HTMLDivElement;
  subtitleSpan: HTMLSpanElement;
  cmdToggle: HTMLButtonElement;
  delBar: HTMLDivElement;
  delToggle: HTMLButtonElement;
  keyBtn: HTMLButtonElement;
  inputEl: HTMLInputElement;
  submitBtn: HTMLButtonElement;
}

export function buildAdvisorPanelDOM(): AdvisorPanelRefs {
  // Panel
  state.panel = document.createElement('div');
  state.panel.style.cssText = PANEL_STYLES;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 10px 12px;
    border-bottom: 1px solid rgba(0, 200, 255, 0.15);
    background: rgba(0, 20, 40, 0.6);
    display: flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
  `;

  state.statusDot = document.createElement('span');
  state.statusDot.style.cssText = `
    width: 6px; height: 6px; border-radius: 50%;
    background: #ef4444; flex-shrink: 0;
  `;

  const titleSpan = document.createElement('span');
  titleSpan.style.cssText =
    'color:#06b6d4;letter-spacing:2px;font-size:10px;text-transform:uppercase;';
  titleSpan.textContent = 'ARIA';

  const subtitleSpan = document.createElement('span');
  subtitleSpan.style.cssText = 'opacity:0.4;font-size:9px;flex:1;';
  subtitleSpan.textContent = 'Asteroid Resource Intelligence Advisor';

  const keyBtn = document.createElement('button');
  keyBtn.title = 'Configure ARIA AI provider';
  keyBtn.style.cssText = `
    background: none;
    border: 1px solid rgba(0, 200, 255, 0.2);
    color: rgba(0, 200, 255, 0.5);
    font-size: 11px;
    cursor: pointer;
    padding: 2px 5px;
    border-radius: 2px;
    font-family: 'Courier New', monospace;
    flex-shrink: 0;
  `;
  keyBtn.textContent = '🔑';

  header.appendChild(state.statusDot);
  header.appendChild(titleSpan);
  header.appendChild(subtitleSpan);
  header.appendChild(keyBtn);
  state.panel.appendChild(header);

  // Commander toggle bar
  const cmdBar = document.createElement('div');
  cmdBar.style.cssText = `
    padding: 4px 12px;
    border-bottom: 1px solid rgba(0, 200, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
    background: rgba(0, 15, 30, 0.5);
  `;
  const cmdLabel = document.createElement('span');
  cmdLabel.style.cssText = 'font-size:9px;letter-spacing:1px;opacity:0.6;';
  cmdLabel.textContent = 'COMMANDER MODE';
  const cmdToggle = document.createElement('button');
  cmdToggle.style.cssText = `
    background: rgba(100, 40, 40, 0.3);
    border: 1px solid rgba(255, 100, 100, 0.3);
    color: #888;
    font-family: 'Courier New', monospace;
    font-size: 9px;
    padding: 2px 8px;
    cursor: pointer;
    border-radius: 2px;
    letter-spacing: 1px;
  `;
  cmdToggle.textContent = 'OFF';
  cmdBar.appendChild(cmdLabel);
  cmdBar.appendChild(cmdToggle);
  state.panel.appendChild(cmdBar);

  // Auto-delegation toggle bar
  const delBar = document.createElement('div');
  delBar.style.cssText = `
    padding: 4px 12px;
    border-bottom: 1px solid rgba(0, 200, 255, 0.1);
    display: none;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
    background: rgba(0, 10, 25, 0.5);
  `;
  const delLabel = document.createElement('span');
  delLabel.style.cssText = 'font-size:9px;letter-spacing:1px;opacity:0.6;';
  delLabel.textContent = 'AUTO-DELEGATE';
  const delToggle = document.createElement('button');
  delToggle.style.cssText = `
    background: rgba(100, 40, 40, 0.3);
    border: 1px solid rgba(255, 100, 100, 0.3);
    color: #888;
    font-family: 'Courier New', monospace;
    font-size: 9px;
    padding: 2px 8px;
    cursor: pointer;
    border-radius: 2px;
    letter-spacing: 1px;
  `;
  delToggle.textContent = 'OFF';
  delBar.appendChild(delLabel);
  delBar.appendChild(delToggle);
  state.panel.appendChild(delBar);

  // Pending actions area
  state.pendingActionsEl = document.createElement('div');
  state.pendingActionsEl.style.cssText = `
    flex-shrink: 0;
    max-height: 200px;
    overflow-y: auto;
    display: none;
    border-bottom: 1px solid rgba(200, 200, 0, 0.15);
    scrollbar-width: thin;
    scrollbar-color: rgba(200,200,0,0.2) transparent;
  `;
  state.panel.appendChild(state.pendingActionsEl);

  // Messages area
  state.messagesEl = document.createElement('div');
  state.messagesEl.style.cssText = `
    flex: 1;
    overflow-y: auto;
    padding: 8px;
    display: flex;
    flex-direction: column;
    gap: 8px;
    scrollbar-width: thin;
    scrollbar-color: rgba(0,200,255,0.2) transparent;
  `;
  state.panel.appendChild(state.messagesEl);

  // Session cap notice (hidden until budget exceeded)
  state.sessionCapNoticeEl = document.createElement('div');
  state.sessionCapNoticeEl.style.cssText = `
    padding: 6px 12px;
    border-top: 1px solid rgba(245, 158, 11, 0.3);
    background: rgba(80, 60, 0, 0.3);
    font-size: 9px;
    color: #f59e0b;
    letter-spacing: 0.5px;
    flex-shrink: 0;
    display: none;
    align-items: center;
    justify-content: space-between;
    gap: 6px;
  `;
  const capNoticeText = document.createElement('span');
  capNoticeText.textContent = 'Session token budget exceeded — using onboard analysis';
  const optBackInBtn = document.createElement('button');
  optBackInBtn.id = 'advisor-opt-back-in';
  optBackInBtn.textContent = 'OPT BACK IN';
  optBackInBtn.style.cssText = `
    background: rgba(80, 60, 0, 0.5);
    border: 1px solid rgba(245, 158, 11, 0.4);
    color: #f59e0b;
    font-family: 'Courier New', monospace;
    font-size: 8px;
    padding: 2px 6px;
    cursor: pointer;
    border-radius: 2px;
    letter-spacing: 0.5px;
    white-space: nowrap;
    flex-shrink: 0;
  `;
  state.sessionCapNoticeEl.appendChild(capNoticeText);
  state.sessionCapNoticeEl.appendChild(optBackInBtn);
  state.panel.appendChild(state.sessionCapNoticeEl);

  // Session usage bar
  state.sessionUsageEl = document.createElement('div');
  state.sessionUsageEl.style.cssText = `
    padding: 4px 12px;
    border-top: 1px solid rgba(0, 200, 255, 0.1);
    font-size: 9px;
    color: rgba(158, 207, 223, 0.6);
    letter-spacing: 0.5px;
    flex-shrink: 0;
  `;
  updateSessionUsageEl();
  state.panel.appendChild(state.sessionUsageEl);

  // Usage summary bar (daily)
  state.usageSummaryEl = document.createElement('div');
  state.usageSummaryEl.style.cssText = `
    padding: 4px 12px;
    border-top: 1px solid rgba(0, 200, 255, 0.1);
    font-size: 9px;
    color: rgba(158, 207, 223, 0.6);
    letter-spacing: 0.5px;
    flex-shrink: 0;
    display: flex;
    justify-content: space-between;
  `;
  updateUsageSummaryEl();
  state.panel.appendChild(state.usageSummaryEl);

  // Loading indicator
  state.loadingEl = document.createElement('div');
  state.loadingEl.style.cssText = `
    padding: 6px 12px;
    display: none;
    align-items: center;
    gap: 6px;
    opacity: 0.6;
    flex-shrink: 0;
  `;
  state.loadingEl.innerHTML = `
    <span class="aria-pulse" style="
      width:6px;height:6px;background:#06b6d4;border-radius:50%;
      animation:ariaPulse 1s ease-in-out infinite;
      display:inline-block;
    "></span>
    <span style="font-size:10px;letter-spacing:1px;">ARIA ANALYZING...</span>
  `;
  state.panel.appendChild(state.loadingEl);

  // Input area
  const inputArea = document.createElement('div');
  inputArea.style.cssText = `
    padding: 8px;
    border-top: 1px solid rgba(0, 200, 255, 0.15);
    display: flex;
    gap: 6px;
    flex-shrink: 0;
  `;

  state.inputEl = document.createElement('input');
  state.inputEl.type = 'text';
  state.inputEl.placeholder = 'Query ARIA...';
  state.inputEl.style.cssText = `
    flex: 1;
    background: rgba(0, 20, 40, 0.8);
    border: 1px solid rgba(0, 200, 255, 0.25);
    color: #9ecfdf;
    font-family: 'Courier New', monospace;
    font-size: 11px;
    padding: 5px 8px;
    outline: none;
    border-radius: 2px;
  `;

  state.submitBtn = document.createElement('button');
  state.submitBtn.textContent = '→';
  state.submitBtn.style.cssText = `
    background: rgba(0, 20, 40, 0.8);
    border: 1px solid rgba(0, 200, 255, 0.25);
    color: #06b6d4;
    font-family: 'Courier New', monospace;
    font-size: 14px;
    padding: 5px 10px;
    cursor: pointer;
    border-radius: 2px;
  `;

  inputArea.appendChild(state.inputEl);
  inputArea.appendChild(state.submitBtn);
  state.panel.appendChild(inputArea);

  return { panel: state.panel, subtitleSpan, cmdToggle, delBar, delToggle, keyBtn, inputEl: state.inputEl, submitBtn: state.submitBtn };
}

export function wireAdvisorPanelEvents(refs: AdvisorPanelRefs): void {
  const { subtitleSpan, cmdToggle, delBar, delToggle, keyBtn, inputEl, submitBtn } = refs;

  keyBtn.addEventListener('click', () => showApiKeyInput());

  cmdToggle.addEventListener('click', () => {
    state.commanderEnabled = !state.commanderEnabled;
    cmdToggle.textContent = state.commanderEnabled ? 'ON' : 'OFF';
    cmdToggle.style.background = state.commanderEnabled ? 'rgba(0, 100, 80, 0.4)' : 'rgba(100, 40, 40, 0.3)';
    cmdToggle.style.borderColor = state.commanderEnabled ? 'rgba(0, 200, 150, 0.4)' : 'rgba(255, 100, 100, 0.3)';
    cmdToggle.style.color = state.commanderEnabled ? '#06d4a4' : '#888';
    subtitleSpan.textContent = state.commanderEnabled
      ? 'Operational Commander'
      : 'Asteroid Resource Intelligence Advisor';
    if (state.commanderToggleCallback) state.commanderToggleCallback(state.commanderEnabled);
  });

  delToggle.addEventListener('click', () => {
    state.delegationEnabled = !state.delegationEnabled;
    delToggle.textContent = state.delegationEnabled ? 'ON' : 'OFF';
    delToggle.style.background = state.delegationEnabled ? 'rgba(80, 80, 0, 0.4)' : 'rgba(100, 40, 40, 0.3)';
    delToggle.style.borderColor = state.delegationEnabled ? 'rgba(200, 200, 0, 0.4)' : 'rgba(255, 100, 100, 0.3)';
    delToggle.style.color = state.delegationEnabled ? '#d4d406' : '#888';
    if (state.delegationToggleCallback) state.delegationToggleCallback(state.delegationEnabled);
  });

  cmdToggle.addEventListener('click', () => {
    delBar.style.display = state.commanderEnabled ? 'flex' : 'none';
    if (!state.commanderEnabled) {
      state.delegationEnabled = false;
      delToggle.textContent = 'OFF';
      delToggle.style.background = 'rgba(100, 40, 40, 0.3)';
      delToggle.style.borderColor = 'rgba(255, 100, 100, 0.3)';
      delToggle.style.color = '#888';
      if (state.delegationToggleCallback) state.delegationToggleCallback(false);
    }
  });

  const optBackInBtn = state.sessionCapNoticeEl!.querySelector<HTMLButtonElement>('#advisor-opt-back-in')!;
  optBackInBtn.addEventListener('click', () => {
    sessionOptBackIn();
    updateSessionUsageEl();
  });

  inputEl.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') handleSubmit();
    e.stopPropagation(); // prevent hotkeys while typing to ARIA
  });

  submitBtn.addEventListener('click', handleSubmit);
}
