import type { PendingAction } from '../../advisor/commanderDelegate';
import { state } from './state';

const ACTION_BTN = `
  background: none;
  border: 1px solid;
  font-family: 'Courier New', monospace;
  font-size: 8px;
  padding: 1px 5px;
  cursor: pointer;
  border-radius: 2px;
  letter-spacing: 0.5px;
`;

export function updatePendingActions(actions: readonly PendingAction[]): void {
  if (!state.pendingActionsEl) return;

  if (actions.length === 0) {
    state.pendingActionsEl.style.display = 'none';
    state.pendingActionsEl.innerHTML = '';
    return;
  }

  state.pendingActionsEl.style.display = 'block';
  state.pendingActionsEl.innerHTML = '';

  // Header with approve/reject all
  const header = document.createElement('div');
  header.style.cssText = `
    padding: 4px 8px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    background: rgba(80, 80, 0, 0.2);
    border-bottom: 1px solid rgba(200, 200, 0, 0.1);
  `;
  const headerLabel = document.createElement('span');
  headerLabel.style.cssText = 'font-size:9px;letter-spacing:1px;color:#d4d406;';
  headerLabel.textContent = `PENDING ACTIONS (${actions.length})`;
  const headerBtns = document.createElement('div');
  headerBtns.style.cssText = 'display:flex;gap:4px;';

  const approveAllBtn = document.createElement('button');
  approveAllBtn.textContent = 'ALL';
  approveAllBtn.title = 'Approve all';
  approveAllBtn.style.cssText = ACTION_BTN + 'border-color:rgba(0,200,100,0.4);color:#22c55e;';
  approveAllBtn.addEventListener('click', () => state.pendingApproveAllCallback?.());

  const rejectAllBtn = document.createElement('button');
  rejectAllBtn.textContent = 'NONE';
  rejectAllBtn.title = 'Reject all';
  rejectAllBtn.style.cssText = ACTION_BTN + 'border-color:rgba(200,100,100,0.4);color:#ef4444;';
  rejectAllBtn.addEventListener('click', () => state.pendingRejectAllCallback?.());

  headerBtns.appendChild(approveAllBtn);
  headerBtns.appendChild(rejectAllBtn);
  header.appendChild(headerLabel);
  header.appendChild(headerBtns);
  state.pendingActionsEl.appendChild(header);

  // Individual actions
  for (const action of actions) {
    const row = document.createElement('div');
    row.style.cssText = `
      padding: 4px 8px;
      border-bottom: 1px solid rgba(200, 200, 0, 0.05);
      display: flex;
      align-items: center;
      gap: 6px;
    `;

    const desc = document.createElement('span');
    desc.style.cssText = 'flex:1;font-size:10px;color:#c8c8a0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;';
    desc.textContent = action.description;
    desc.title = action.reasoning || action.description;

    const approveBtn = document.createElement('button');
    approveBtn.textContent = 'Y';
    approveBtn.title = 'Approve';
    approveBtn.style.cssText = ACTION_BTN + 'border-color:rgba(0,200,100,0.4);color:#22c55e;';
    approveBtn.addEventListener('click', () => state.pendingApproveCallback?.(action.id));

    const rejectBtn = document.createElement('button');
    rejectBtn.textContent = 'N';
    rejectBtn.title = 'Reject';
    rejectBtn.style.cssText = ACTION_BTN + 'border-color:rgba(200,100,100,0.4);color:#ef4444;';
    rejectBtn.addEventListener('click', () => state.pendingRejectCallback?.(action.id));

    row.appendChild(desc);
    row.appendChild(approveBtn);
    row.appendChild(rejectBtn);
    state.pendingActionsEl.appendChild(row);
  }
}
