import { getBudgetCap, setBudgetCap } from '../../advisor/usage';
import { state } from './state';
import { updateUsageSummaryEl } from './usageDisplay';

export function showApiKeyInput(): void {
  if (!state.panel) return;
  const existing = document.getElementById('aria-key-overlay');
  if (existing) {
    existing.remove();
    return;
  }

  const overlay = document.createElement('div');
  overlay.id = 'aria-key-overlay';
  overlay.style.cssText = `
    position: absolute;
    top: 42px;
    left: 0;
    right: 0;
    background: rgba(0, 10, 25, 0.97);
    border-bottom: 1px solid rgba(0, 200, 255, 0.2);
    padding: 10px 12px;
    z-index: 10;
  `;

  const providerLabel = document.createElement('div');
  providerLabel.style.cssText =
    'font-size:9px;color:#06b6d4;letter-spacing:1px;margin-bottom:4px;opacity:0.7;';
  providerLabel.textContent = 'LLM PROVIDER';

  const selectStyle = `
    width: 100%;
    background: rgba(0, 20, 40, 0.8);
    border: 1px solid rgba(0, 200, 255, 0.25);
    color: #9ecfdf;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    padding: 4px 6px;
    outline: none;
    border-radius: 2px;
    margin-bottom: 8px;
  `;

  const providerSelect = document.createElement('select');
  providerSelect.style.cssText = selectStyle;
  const providers = [
    { value: 'anthropic', label: 'Anthropic (Claude)' },
    { value: 'groq', label: 'Groq (GPT-OSS)' },
    { value: 'proxy', label: 'Playtest Proxy' },
    { value: 'heuristic', label: 'Heuristic (Offline)' },
  ];
  for (const p of providers) {
    const opt = document.createElement('option');
    opt.value = p.value;
    opt.textContent = p.label;
    if (p.value === state.currentProvider) opt.selected = true;
    providerSelect.appendChild(opt);
  }

  const placeholders: Record<string, string> = {
    anthropic: 'sk-ant-...',
    groq: 'gsk_...',
    proxy: 'Proxy key...',
  };

  const label = document.createElement('div');
  label.style.cssText =
    'font-size:9px;color:#06b6d4;letter-spacing:1px;margin-bottom:4px;opacity:0.7;';
  label.textContent = 'API KEY';

  const row = document.createElement('div');
  row.style.cssText = 'display:flex;gap:6px;';

  const keyInput = document.createElement('input');
  keyInput.type = 'password';
  keyInput.placeholder = placeholders[state.currentProvider] || 'API key...';
  keyInput.style.cssText = `
    flex: 1;
    background: rgba(0, 20, 40, 0.8);
    border: 1px solid rgba(0, 200, 255, 0.25);
    color: #9ecfdf;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    padding: 4px 6px;
    outline: none;
    border-radius: 2px;
  `;

  providerSelect.addEventListener('change', () => {
    keyInput.placeholder = placeholders[providerSelect.value] || 'API key...';
    label.textContent = providerSelect.value === 'proxy' ? 'PROXY KEY' : 'API KEY';
  });

  const saveBtn = document.createElement('button');
  saveBtn.textContent = 'SAVE';
  saveBtn.style.cssText = `
    background: rgba(0, 100, 150, 0.4);
    border: 1px solid rgba(0, 200, 255, 0.3);
    color: #06b6d4;
    font-family: 'Courier New', monospace;
    font-size: 9px;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 2px;
    letter-spacing: 1px;
  `;
  const budgetLabel = document.createElement('div');
  budgetLabel.style.cssText =
    'font-size:9px;color:#06b6d4;letter-spacing:1px;margin-bottom:4px;margin-top:8px;opacity:0.7;';
  budgetLabel.textContent = 'DAILY TOKEN BUDGET';

  const budgetInput = document.createElement('input');
  budgetInput.type = 'number';
  budgetInput.min = '1000';
  budgetInput.step = '1000';
  budgetInput.value = String(getBudgetCap());
  budgetInput.style.cssText = `
    width: 100%;
    background: rgba(0, 20, 40, 0.8);
    border: 1px solid rgba(0, 200, 255, 0.25);
    color: #9ecfdf;
    font-family: 'Courier New', monospace;
    font-size: 10px;
    padding: 4px 6px;
    outline: none;
    border-radius: 2px;
    box-sizing: border-box;
  `;

  saveBtn.addEventListener('click', () => {
    if (state.providerCallback) state.providerCallback(providerSelect.value);
    const key = keyInput.value.trim();
    if (state.apiKeyCallback) state.apiKeyCallback(key);
    const cap = parseInt(budgetInput.value, 10);
    if (!Number.isNaN(cap) && cap > 0) {
      setBudgetCap(cap);
      updateUsageSummaryEl();
    }
    overlay.remove();
  });

  row.appendChild(keyInput);
  row.appendChild(saveBtn);
  overlay.appendChild(providerLabel);
  overlay.appendChild(providerSelect);
  overlay.appendChild(label);
  overlay.appendChild(row);
  overlay.appendChild(budgetLabel);
  overlay.appendChild(budgetInput);
  state.panel.appendChild(overlay);
  keyInput.focus();
}
